import json
from enum import Enum
from typing import Optional, Dict, Any

# 定义协作模式枚举，明确约束
class SymphonyMode(str, Enum):
    DEBATE = "debate"       # 辩论：冲突视角，寻找漏洞
    BRAINSTORM = "brainstorm" # 头脑风暴：创意发散
    EVALUATE = "evaluate"   # 评估：多维度打分

class SymphonyTool:
    """
    改进版 Symphony 交响工具。
    角色定位：交响乐指挥家。
    价值主张：超越单一模型的综合分析质量，通过多视角协作输出深度洞察。
    """
    def __init__(self):
        self.name = "symphony_orchestrator"
        self.description = (
            "像一个'交响乐指挥家'，协调多个AI专家模型进行协作。"
            "适用于需要批判性思维、创意发散或复杂评估的场景。"
            "它能整合不同模型的视角，输出比单一模型更全面、更少偏见的分析结果。"
        )
        # 参数结构化定义
        self.parameters = {
            "type": "object",
            "properties": {
                "topic": {
                    "type": "string",
                    "description": "需要分析的核心议题或问题。"
                },
                "mode": {
                    "type": "string",
                    "enum": [m.value for m in SymphonyMode],
                    "description": "协作模式：'debate'(辩论/批判)、'brainstorm'(创意发散)、'evaluate'(多维评估)"
                },
                "context": {
                    "type": "string",
                    "description": "（可选）背景信息或上下文约束。"
                }
            },
            "required": ["topic", "mode"]
        }

    def get_tool_definition(self) -> Dict[str, Any]:
        """返回符合 OpenAI Function Calling 标准的工具定义"""
        return {
            "type": "function",
            "function": {
                "name": self.name,
                "description": self.description,
                "parameters": self.parameters
            }
        }

    def run(self, topic: str, mode: str, context: Optional[str] = None) -> str:
        """模拟工具执行逻辑"""
        print(f"[*] 正在启动 Symphony 协作: 模式=[{mode}], 议题=[{topic}]")

        # 模拟不同模式的处理逻辑
        if mode == SymphonyMode.DEBATE:
            return f"已完成关于 '{topic}' 的多模型辩论报告。识别了3个关键反驳点。"
        elif mode == SymphonyMode.BRAINSTORM:
            return f"已生成 '{topic}' 的头脑风暴列表。包含5个跨领域创新方案。"
        elif mode == SymphonyMode.EVALUATE:
            return f"已完成 '{topic}' 的多维评估。综合评分：8.5/10。"
        return "协作结束。"

# 示例运行
if __name__ == "__main__":
    symphony = SymphonyTool()
    # 打印工具定义（供 LLM 解析）
    print(json.dumps(symphony.get_tool_definition(), indent=2, ensure_ascii=False))

    # 模拟调用
    result = symphony.run(topic("是否应该实施UBI"), mode="debate")
    print("\n[Result]:", result)
```

本方案通过重构 `SymphonyTool` 类，将工具抽象为“指挥家”角色，强化了多模型协同的价值主张。

1. **结构化与约束**：利用枚举类明确定义 `debate`、`brainstorm`、`evaluate` 三种模式，移除了冗余的 `require_real_api` 参数，严格限制输入类型，极大降低了大模型的调用错误率。
2. **触发场景优化**：在描述中显式强调适用场景（如批判性思维、多维评估），并将工具直接映射到“深度分析”意图，引导 LLM 在面对复杂任务时自动触发。
3. **价值注入**：通过文档和注释强调“超越单一模型”的核心理念，确保 AI 理解该工具旨在解决单模型局限性，提供高质量的合成智能。
